OS
Debian GNU/Linux 10  -- Chromebook linux 98.0.4758.107 (Official Build) (64-bit)

May we assist you in trying to fix this in Verilator yourself? Maybe :) I didn't see a similar issue, and I thought existing issues with various compilers had been addressed already, but perhaps this is some fringe issue with Debian g++.

Workarounds:
1. Refactor the SV code to avoid a case-stmt (if-else)
2. Refactor the SV code to avoid ++ or --, such as n = n + 1'b1;
3. Do not compile with --trace or --coverage

My local test_regress is:
t_case_default.v:
```
module t (/*AUTOARG*/
   // Inputs
   clk
   );

   input clk;

   integer cyc; initial cyc = 0;

   logic      push_valid, push_ready;
   logic      pop_valid, pop_ready;

   always @ (posedge clk) begin
      cyc <= cyc + 1;
      {push_valid, push_ready, pop_valid, pop_ready}
        <= 4'($urandom);

     if (cyc > 100) begin
	     $write("*-* All Finished *-*\n");
       $finish();
     end

   end


  // real RTL code snippet:

  logic [3:0] count_d;
  logic [3:0] count_q = '0;

  always_ff @(posedge clk) begin : flops
    count_q   <= count_d;
  end

  logic  push, pop;
  assign push = push_valid && push_ready;
  assign pop = pop_valid && pop_ready;

  // Uncomment one of these define lines to get Verilator to compile
//`define HACK_TO_PASS
//`define HACK_TO_PASS2


`ifdef HACK_TO_PASS

  always_comb begin : update_counts
    count_d = count_q;

    // refactored case stmt as if-else-if
    if (push && !pop) begin
      count_d++;
    end else if (!push && pop) begin
      count_d--;
    end
  end
`else

`ifdef HACK_TO_PASS2
  always_comb begin : update_counts
    count_d = count_q;

    case ({push, pop})
    2'b10: begin
      // refatored ++ as n + 1'b1.
      count_d = count_d + 1'b1;
    end
    2'b01: begin
      count_d = count_d - 1'b1;
    end
    default : ;
    endcase // case ({push, pop})
  end
`else

  // This is the one that fails:
  always_comb begin : update_counts
    count_d = count_q;

    case ({push, pop})
    2'b10: begin
      count_d++; // issue is here, case with ++, --
    end
    2'b01: begin
      count_d--;
    end
    default : ;
    endcase // case ({push, pop})
  end
`endif
`endif


endmodule

```

